export const RULES = [
  { id: 'R1', rule: '<span class="eva">qo-</span> = <span class="heb-sm">וְ</span> (Vav conjunctive) an jedem Wortanfang — <strong>ausschließlich Sprache B in Quires A+B</strong>; in Sprache A vollständig absent (gilt mit vollem Geltungsbereich nur für Quires A+B — s. R33, R47)', evidence: 'qokedam, qokol, qokeedy (f57r, f103r); f001r Spr. A: 0 Belege in 260 Tokens ★★★★★; Ausnahmen ab Quire C: s. R33 (emergierend) + R47 (Quire H vollständig integriert)', stars: '★★★★★' },
  { id: 'R2', rule: '<strong>o-Positionsdetermination (R2-ext, v7.5):</strong><br><span class="eva">o-</span> am Wortanfang = <span class="heb-sm">עַ</span> (Ayin, konsonantisch) — ausnahmslos; <span class="eva">o</span> im Wortinneren = <span class="heb-sm">ֹ</span> (Ḥolam, Vokalmarker) — ausnahmslos. Kein Ermessensspielraum — die Dualfunktion ist vollständig positionell determiniert (vgl. Mater lectionis-Funktion von Vav/Yod im spätbiblischen Hebräisch: positionell Konsonant <em>oder</em> Vokalmarker).<br><strong>Negativtest:</strong> Kein Lexikoneintrag im gesamten validierten Corpus verletzt diese Positionsregel — 0 Gegenbeispiele in 140+ Einträgen.', evidence: 'Wortanfang → Ayin: okol, okoldm, okaiin, odol, okaiin, otor, otam, okchan; wortintern → Ḥolam: qokol (קוֹ+כֹּל), okoldm (עַל+כֹּל+דָּם), sokar, ytor, ychor, shol; Negativtest (v7.5): 0 Gegenbeispiele in 140+ Lexikoneinträgen ✓', stars: '★★★★' },
  { id: 'R3', rule: 'y-initiale Wörter = Imperfekt 3. Sg. Mask.', evidence: 'yteechy, yshdal, ykchaiin, ycheor, ychor; f1r: ykal, ykaiin, yshey, ycho, yto, ycheey (6 neue Belege) — >11 Belege / ≥8 Folios', stars: '★★★★★' },
  { id: 'R4', rule: 't-initiale Wörter = Imperfekt 3. Sg. Fem. / 2. Sg.', evidence: 'taiir; tsheoarom', stars: '★★★★' },
  { id: 'R5', rule: '<span class="eva">shedy</span> und <span class="eva">chedy</span> kommen nie im selben Absatz vor', evidence: '15 Zeilen nur chedy, 17 nur shedy, 5 beide (lange Zeilen)', stars: '★★★★' },
  { id: 'R6', rule: 'Zeilenabschluss <span class="eva">sheol/shol</span> = Tod-Prognose; <span class="eva">or</span> = Heilungsprognose', evidence: 'f103r: 8× sheol am Zeilenende; P.17 endet or·aiin', stars: '★★★★' },
  { id: 'R7', rule: '<span class="eva">daiin</span> am Zeilenanfang = Paragraphen-Öffner', evidence: '3× Zeilenanfang f103r; f57r P.5; f10v: 8×', stars: '★★★★' },
  { id: 'R8', rule: '<span class="eva">-aiin</span> als Suffix = <span class="heb-sm">עַיִן</span> (Auge) diagnostisch', evidence: 'okaiin, qokaiin je 10–11×', stars: '★★★★' },
  { id: 'R9', rule: 'Refrain-Wörter erscheinen 3–5× pro Folio in Anker-Position', evidence: 'dam in f57r (4×), dal in f103r P.1 (3×), daiin in f10v (8×)', stars: '★★★★' },
  { id: 'R10', rule: '<span class="eva">-ody</span>-Paragraphen = eigenständiges Listenregister; nie mit chedy/shedy kombiniert', evidence: 'f57r P.3–P.4: strikte Exklusion', stars: '★★★' },
  { id: 'R11', rule: 'Paragraphen-Ende mit <span class="eva">=</span> = Abschlussformel', evidence: 'kaiim=, dom=, daiin=, chckhan=, chal=; f57r cphedom=; f1r T1–T4 (alle 6 Transkriptoren einig); f1v P4-Kolophon chokody=, P10-Kolophon chodar= — 6 neue Belege. <em>Sektionsabschluss-Variante (1 Beleg, f24v P.16): <span class="eva">odaiim=</span> (<span class="heb-sm">עַ+דִּינִים</span>) in Final-Kolophon des letzten Quire-C-Paragraphen — Plural-Intensiv als Super-Abschluss. Eigenständige Regel bei 2+ Sektionsabschlüssen zu erheben. (ex R57, v8.1)</em>', stars: '★★★★' },
  { id: 'R12', rule: 'Trägersatz-Muster: P.1 (Relativsatz) → P.2 (Hauptsatz mit sar)', evidence: 'f57r P.9; f103r P.1→P.2', stars: '★★★' },
  { id: 'R13', rule: 'Paragraphen ohne Randstern = positives Prognose-Vokabular (<span class="eva">or, lor·aiin</span>)', evidence: 'f103r P.3,17,20; f103v: 5/5 or-Paragraphen sternlos', stars: '★★★★' },
  { id: 'R14', rule: '<strong>R14 (v8.4) — <span class="eva">{plant}</span>-Marker: Strukturelle und pharmakologische Doppelfunktion</strong><br><strong>Ebene 1 (horizontal):</strong> Text links von <span class="eva">{plant}</span> = Diagnose/Indikation; Text rechts = Therapie/Prognose (unverändert).<br><strong>Ebene 2 (vertikal, NEU):</strong> Die vertikale Position von <span class="eva">{plant}</span> im Seitenlayout entspricht dem Pflanzenteil auf der Illustration, der im angrenzenden Textsegment verschrieben wird. Zonen von oben nach unten:<br><strong>FLOS/FRUCTUS</strong> (Blüte/Frucht)<br><strong>CAULIS</strong> (Stiel/Ähre)<br><strong>FOLIUM</strong> (Blatt)<br><strong>RADIX</strong> (Wurzel/Rhizom).<br><em>Korollar: Text ohne <span class="eva">{plant}</span>-Marker oder über der gesamten Pflanze = Ganzpflanzen-Präparat ohne Teilunterscheidung.</em><br><strong>Farbcode-Korollar (dreistufig, ★★★★★): Ebene 1</strong> — alle Wurzeln unabhängig von Farbe = kein Verschreibungstext (13 Belege, 0 Gegenbeispiele; v8.4: +f002r Beleg 11 dunkel übermale Wurzel, +f007r Beleg 12 orange-rote Rhizomwurzel; v8.7: +f31r Beleg 13 pharmakologisches Dunkelrot-Rhizom Tanacetum parthenium).<br><strong>Ebene 2</strong> — homogene Terracotta/Dunkelrot-Flächenfüllung (opak, gleichmäßig) an beliebigem Pflanzenteil = kein Text (★★★★★; f010r Oval-Strukturen = Erstbeleg Nicht-Wurzel-Rot nach Quire-A-Retroanalyse; f25r Stängelknoten-Bohnen; insgesamt 3 Nicht-Wurzel-Belege).<br><em>Drei-Kategorien-Verfeinerung (v8.4): Illustrationslinien-Rot (Strich/Linienzüge) ≠ pharmakologisches Dunkelrot (Fläche). FLOS-therapeutisches Rot (Punkte/Textur für Früchte, z.B. f009r Ähre) ist prescribiert — Text vorhanden. Die Unterscheidung folgt der Maltechnik: <strong>Fläche</strong> = pharmakologisch stumm; <strong>Linie/Textur</strong> = illustrativ/botanisch; <strong>FLOS-Dotted</strong> = prescribierter Fruchtbereich.</em><br><strong>Ebene 3</strong> — grün = prescribiert (Text vorhanden); f25r: grüne Blätter (Text) neben dunkelroten Bohnen (kein Text) auf demselben Folio — direkter interner Kontrast. Reeds-Dokumentation <code>Colors: green,dark-red</code> auf f25r bestätigt Farbzuordnung unabhängig.', evidence: 'f1v–f10v: 100 % konsistent (Ebene 1); Stolfi f16r: „interrupted by the plant\'s flower" — Blüten-Position explizit dokumentiert ★★★★★; <span class="eva">pol</span> (Frucht-Term) an Frucht-Position f22r P.1 ★★★★★; f19r: gesamter Text auf Blüten-Höhe, <span class="eva">saiin+chor</span> semantisch kohärent mit Kornblumen-Pharmakologie (Augenwasser, Konjunktivitis) ★★★★★; f14r/f15r/f22r/f28r/f30v: rote Wurzeln ohne Text — 5 Belege ★★★★; f13r (v8.4): Inula helenium orange-rote Hauptwurzel ohne Text — 10. Beleg ★★★★★; f002r (v8.4): dunkel übermale Centaurea-Wurzel ohne Text — Beleg 11 ★★★★★; f007r (v8.4): orange-rote Sternblumen-Rhizomwurzel ohne Text — Beleg 12 ★★★★★; f31r (v8.7): pharmakologisches Dunkelrot-Rhizom Tanacetum parthenium ohne Text — Beleg 13 ★★★★★; f25r: dunkelrote Bohnen an Stengelknoten ohne Text — Erstbeleg Nicht-Wurzel-Rot-Muster; f010r (v8.4): rote Oval-Strukturen (Nicht-Wurzel!) ohne Text — 3. Nicht-Wurzel-Beleg → Ebene 2 ★★★★★; f009r: rote Punkt-Ähre MIT Text = FLOS-therapeutisches Rot (dotted) ≠ homogenes Terracotta — Drei-Kategorien-Verfeinerung bestätigt; 21/21 analysierten Folios zeigen selektive Pflanzenteil-Annotation (Muster I)', stars: '★★★★★' },
  { id: 'R15', rule: 'Paradigma-Wiederholungsreihen (×2–×5): Adjektiv/Verb mit Vokal- oder Präfixvariation —<br><strong>Typ A</strong> (direkt nebeneinander: <span class="eva">chor·chor</span>);<br><strong>Typ B</strong> (mit Zwischentext: <span class="eva">chor…chor</span>);<br><strong>Typ B-Dreistufig</strong> (Verb → Nomen → Direktional mit Zwischentext: <span class="eva">ychor·chor·[ZT]·chory</span>);<br><strong>Typ C</strong> (drei phonologisch verwandte sh/chor-Stämme in direkter Folge: <span class="eva">shor·chor·sho</span> — semantisches Spannungsfeld: Licht-Zeichen → Pupille/Heilungskern → Scheol/Tod);<br><em><strong>Typ D</strong> (Kand., 1 Beleg): Drei semantisch synonyme Heilungsterme in Kolophon-Finalposition (f21r P.7: <span class="eva">shoeor·cheor·cthor</span>). Validierungsfrist abgelaufen — strukturelle Verwandtschaft zu Typ B gesichert, Eigenständigkeit nicht. (ex R52, v8.1)</em>', evidence: 'f1v P.3 (ckhy·ckho·ckhy); f10r P8 (chor·chor·cholor); f20r P.13 (chor·chor — Typ A); f21r P.12 (ykeea·<strong>chor</strong>·sheey·ysheol·<strong>chor</strong>·chol·daiin·chkaiin= — Typ B, 4. Beleg); f22v P.7 (<span class="eva">ychor·chor·qokchol·chory</span> — Dreistufig-Schema: Verb → Nomen → Direktional mit Zwischentext, Typ B, 5. Beleg); f23r P.7 (<span class="eva">qokchol·dar·qokchol</span> — nominale Rahmendopplung mit dar (Leuchtender) als Zwischentext, Typ B nominal, 6. Beleg); f1r P3.L15 (<span class="eva">chol·chol</span> — Typ A, 7. Beleg, 4/4 Transkriptoren); f1r P4.L26 (<span class="eva">keey·keey</span> — Typ A, 8. Beleg, 3/4 Transkriptoren); f1r P4.L23 (<span class="eva">dar…dar</span> — Typ B mit Zwischentext, 9. Beleg, 4/4); f29r P.8 (<span class="eva">shor·chor·sho</span> — Typ C, 10. Beleg, max. Diagnosebreite: Licht-Zeichen → Pupille → Scheol, 1 Beleg semantisch kohärent); f33v P.6 (<span class="eva">chdy·chdy</span> — Typ A, 11. Beleg, H/C/F/U = 100 %); f34r P.5 (<span class="eva">shedy·shedy</span> — Typ A, 12. Beleg); f34r P.13 (<span class="eva">qokar·qokar</span> — Typ B, 13. Beleg) — 13 Belege / 9 Folios → ★★★★★', stars: '★★★★★' },
  { id: 'R16', rule: '<strong>R16 (v8.3) — Mehrfach-<span class="eva">{plant}</span>: Zwei Ebenen</strong><br><strong>Typ 1 (Horizontal-Dreisegment, unverändert):</strong> Alle <span class="eva">{plant}</span>-Marker auf <em>derselben</em> vertikalen Höhe — [Diagnose] {plant} [Brückenterm] {plant} [Prognose] — ein einziger Pflanzenteil.<br><strong>Typ 2 (Vertikal-Zweiteilverschreibung, NEU):</strong> <span class="eva">{plant}</span>-Marker auf <em>verschiedenen</em> vertikalen Höhen — jeder Marker kennzeichnet einen anderen Pflanzenteil; Textsegmente zwischen Markern = separate Verschreibungen für separate Teile. f15r (alle Paragraphen mit Doppel-{plant}) = Typ 2 (zwei Blütenknospen, je eigene Textspalte).', evidence: 'Typ 1: f2r P.2–P.6: Kornblume mit drei Stielen → drei Segmente auf gleicher Höhe; Typ 2: f15r bilateral-Blüte (zwei Knospen, je eigene Textspalte auf Blüten-Höhe) ★★★★; f30r P.11+P.12: zwei <span class="eva">{plant}</span>-Marker auf Blatt-/Rhizom-Höhe → Typ 2 zu prüfen; Abgrenzungskriterium: bei Typ 1 gleiche Bildzeile, bei Typ 2 mindestens eine Bildzone Abstand', stars: '★★★★' },
  { id: 'R17', rule: 'Spr. A: <span class="eva">shol</span> (apokor.) medial; Spr. B: <span class="eva">sheol</span> (Vollform) am Zeilenende', evidence: 'f4r–f10v: shol medial (20+×); f103r: sheol final (8×); Zodiak-Register bestätigt ★★★★: f72r1 R1 shol (2× medial) / f72r1 R2 sheol (direkt vor gap = 5. Register-Bestätigung)', stars: '★★★★' },
  { id: 'R18', rule: 'Diagnosepaar <span class="eva">shol · chaiin</span> = abwägende Prognose; nie einzeln in abwägenden Kontexten', evidence: 'f4r P.2, f4v P.3, f6v P.2, f8v P3, f9r P2', stars: '★★★★' },
  { id: 'R19', rule: 'Intensivierungsrhetorik: ×2 = Emphase; ×3 = absolutes Urteil; ×4 + קַיָאם = rechtskräftiges Urteil.<br><em><strong>Typ E (★★★ Kand.): ABAB-Verflechtung</strong> — zwei semantisch komplementäre positive Heilungsterme in Sequenz A·B·A·B = doppelt-verflochtene Intensivierung. Distinkt von Typ A (AA) und Typ B (AXA). Erstbeleg: f30r P.11 <span class="eva">cheor·chey·cheor·chey</span> (Licht-Leben-Licht-Leben).</em>', evidence: 'Doppel: f4r,f6r,f8v,f10r; Tripel: f5v P.3; Vierfach: f8r P3.19; <span class="eva">daiin·daiin</span> (Doppelurteil): f19v P.4 (1. Beleg) + f21v P.4 (2. Beleg, ★★★ Kand. bestätigt); Zodiak-Register ★★★: <span class="eva">otam·otam·chotam</span> f72r1 R1 (dreistufige Nominal-Intensivierung: einfach → ×2 → Komparativ ko+X per R35) + <span class="eva">otaiin·otain</span> f72r1 S1.8 (Kurzform-Paradigmawiederholung); f29r P.6: <span class="eva">shor·shor</span> — shor-Dopplung (★★★ Kand.); f30r P.11: <span class="eva">cheor·chey·cheor·chey</span> — Corpus-Erstbeleg ABAB-Verflechtung (Typ E ★★★ Kand., alle H/C/F einig). <em>Rahmungsvariante (1 Beleg, f24r P.16): <span class="eva">dal·dam·dal</span> = doppelte Schwäche rahmt Blutbefund — Sandwich-Analogon zu R15-Typ-B-Dopplung. Eigenständige Regel bei 2+ Belegen zu erheben. (ex R54, v8.1)</em>', stars: '★★★★' },
  { id: 'R20', rule: 'Direktionales Antonymenpaar: <span class="eva">lor</span> (לְאוֹר) ↔ <span class="eva">lshol</span> (לְשׁוֹל)', evidence: 'f6v P.11 (lor), f7v P.6 (lshol); identische l-Morphologie', stars: '★★★★★' },
  { id: 'R21', rule: 'Schlussformeln mit =-Marker: kaiim=, dom=, daiin=, chckhan=. <em>Erweiterte Inventar-Einträge: <span class="eva">qor·chain·cthorchy=</span> (f30r P.7, Dreiterm-Positiv: Licht–Auge-des-Lebens–vollständige-Heilung-der-Blässe); <span class="eva">shol·chokcheey·daiin·kchydy=</span> (f30v P.11, Vierterm Scheol-Leben-Urteil-Blässe — Lebensvorschrift zwischen Scheol und Urteil).</em>', evidence: 'f6r, f6v, f8r, f8v, f10v — konsistentes Inventar; f30r P.7 + f30v P.11 — zwei neue Kolophon-Typen (beide H/C/F vollständig einig)', stars: '★★★★' },
  { id: 'R22', rule: 'Folio-übergreifendes Fallverlaufs-Narrativ: Prognose-Eskalation korrespondiert mit botanischer Ikonographie', evidence: 'Quire A: Heilkräuter → Mandragora → Mohn → Aronstab', stars: '★★★' },
  { id: 'R23', rule: 'Kurztitel-Format (Siman): 2 Wörter + =-Marker fasst Paragraphenbefund zusammen', evidence: 'f8r T1–T3 (ocho·daiin=, okokchodm=, schol·sair=); f9r T10', stars: '★★★★' },
  { id: 'R24', rule: '<span class="eva">shol·dy·…·shol</span> — Emphase-Dopplung mit Genitiv-Brücke <span class="heb-sm">דִּי</span>', evidence: 'f13r P.1: torshor·opchy·shol·dy·qopchy·shol — einmaliges Strukturmuster', stars: '★★★' },
  { id: 'R25', rule: '<span class="eva">dy × n</span> — Genitivkette als Intensitätsskala: ×1 Standard / ×2 Emphase / ×3 absoluter Superlativ. <em>Die ×3-Extremform kann als fusioniertes Token <span class="eva">dydyd</span> auftreten — ein Einzelbeleg (f1r P3.17). Diese Schreibervariante ändert die Intensitätssemantik nicht. (ex R32, v8.1)</em>', evidence: 'f14r P.10, f14v P.7 (×2); f14v P.6 (×3, einmalig) — Kandidat', stars: '★★★' },
  { id: 'R28', rule: '<span class="eva">y+t+[Terminus]</span> — intensivierte/aspektuell verstärkte Imperfektform: y- (3. Sg. Mask.) + t- (3. Sg. Fem. / temporal) kombiniert — <strong>★★★ validiert (v8.1) → ★★★★ (v8.7)</strong>. <em>Erweiterung (v8.7): Die Konstruktion gilt für alle validierten Licht-, Heilungs- und Scheol-Stämme: <span class="eva">ytsho</span> (f32r P.4) = y+t+sho (Scheol-Stamm) — 3. Folio-Beleg; kein Stammgruppen-Constraint mehr. R28 ist vollständig stammübergreifend validiert.</em>', evidence: 'ytchor (f16v P.2), ytchy (f16v P.5); f28r P.9: ytchol + yteol (2 aufeinanderfolgende y+t-Verben im Kolophon); f29v P.2: ytchor (Zweitbeleg → ★★★★ in Verbformen) — R43 erfüllt: f16v + f28r = 2 Folios → ★★★ validiert; f30v P.5: ytor = y+t+or (or-Stamm); f32r P.4: <span class="eva">ytsho</span> = y+t+sho (Scheol-Stamm) — 3. Folio-Beleg (f16v + f28r + f32r), diverse Termini → ★★★★', stars: '★★★★' },
  { id: 'R29', rule: '<span class="eva">oto+or</span> erscheint nur in Finalposition unmittelbar vor einem Quire-Abschlusskolophon = positive Prognose-Abschluss-Geste', evidence: 'otor in f16v P.12 (vor sokar·oaorar= Quire-B-Abschluss); Zodiak: f71v R2 (eingebettet zwischen shepchol + sheo·shopcho — liturgische Prognose-Formel) + f72r1 R2 (direkt vor chokaiin, am R2-Segment-Ende) — 4 Belege gesamt, ★★★ Kand.', stars: '★★★' },
  { id: 'R30', rule: '<span class="eva">sho-</span> + Nomen = Scheol-Lokalisierung / Todesform des Nomens — Kandidat', evidence: 'shodain (f001r P3.12), shoaiin (f001r P4.24), shokcheey (f001r P4.22); shoiin (f13v) ★★★★', stars: '★★★' },
  { id: 'R31', rule: 'Temperatur-Antonymenpaar <span class="eva">kor</span> (<span class="heb-sm">קֹר</span>, Kälte) ↔ <span class="eva">kchom</span> (<span class="heb-sm">כְּ+חֹם</span>, Fieber) in aufeinanderfolgenden Zeilen = hippokratisches Diagnostikschema — Kandidat', evidence: 'f001r P3.15 (kor) + P3.16 (kchom); Parallele zu lor↔lshol (R20)', stars: '★★★' },
  { id: 'R33', rule: '<span class="eva">qo-</span>-Präfix tritt ab Quire C (Beinecke Quire III) auch in <strong>Sprache-A-Texten</strong> auf — Quire C ist eine dialektale Übergangszone mit folio-intern ansteigender qo-Integration: bC1 (f17) ~5 %, bC2 (f18) ~4–5 %, bC3 (f19) ~10 % (= Quire-H-äquivalent). R1 (qo- = B-exklusiv) gilt mit vollem Geltungsbereich nur für Quires I–II. Ab Bifolio bC3 ist vollständige qo-Integration zu erwarten. Vollständige Integration in Quire H: s. R47 — Kandidat', evidence: 'f17r: 7 qo-Formen (Spr. A); f17v: 6 qo-Formen (Spr. A) — 13 Belege in ~250 Token (~5,2 %); f18r/v (bC2): 8–10 qo-Formen in ~200 Token (~4–5 %); f19r/v (bC3): ~18 qo-Formen in ~175 Token (~10 %) — überschreitet Quire-H-Dichte; 0 Belege in Quires A+B Spr. A (~800 Token); f58r (Quire H, Spr. A): 28+ qo-Formen in ~350 Token (~8 %) — Vollintegration, s. R47', stars: '★★★' },
  { id: 'R34', rule: '<span class="eva">sheol</span> (Vollform <span class="heb-sm">שְׁאוֹל</span>) erscheint ab Quire C auch in Sprache-A-Texten am Paragraphenende — <span class="eva">shol</span> (apokor.) bleibt dominant; R17 gilt uneingeschränkt nur für Quires I–II — Kandidat', evidence: 'f17v P.13: ykeor·chol·chol·cthol·chkor·sheol-{plant} — Erstbeleg Spr. A sheol am Paragraphenende; 0 Belege in Quires A+B Spr. A', stars: '★★★' },
  { id: 'R35', rule: 'Dopplung <span class="eva">chol·chol</span> (<span class="heb-sm">כֹּל·כֹּל</span> = alles-alles) = Vollheilungs-Emphase vor nachfolgender Todesformel — erweitert R19-Intensivierungsschema auf Nominalstämme — <strong>★★★ validiert</strong>', evidence: 'f17v P.13: chol·chol·cthol·chkor·sheol — Erstbeleg; f29v P.2 (Zweitbeleg) + f29v P.3 (Drittbeleg) — Foliobeleg-Cluster auf demselben Folio in aufeinanderfolgenden Paragraphen; R43 erfüllt: f17v + f29v = 2 Folios → ★★★ validiert; Parallele zu chol·chol·chol auf f8v (R19)', stars: '★★★' },
  { id: 'R36', rule: 'Dopplung <span class="eva">dar·dar</span> (<span class="heb-sm">דַּר·דַּר</span>) = Bilateral-/Intensiv-Dopplung für <span class="eva">dar</span> (leuchtend/Licht-davon) in ophthalmologischem und kosmologischem Kontext — mögliche Bedeutung: bilaterale Augenbeteiligung oder maximale Lichtintensivierung als diagnostische Emphase — <strong>★★★★★</strong> (register-übergreifend: Botanik + Kosmogramm)', evidence: 'f18r P.6: dar.dar — Corpus-Erstbeleg (★★★ Kand.); f26v P.6: dar…dar — 2. Beleg (Typ B mit Zwischentext) → R43 erfüllt → ★★★★; f69r R.17: dair.dar= — 3. Beleg (Typ A, Terminal, kosmologisch); f69r R.22: dary.dar — 4. Beleg (Typ A, direktional) → 3 Folios · 4 Belege · register-übergreifend (botanisch f18r+f26v, kosmologisch f69r) · 0 Gegenbeispiele → ★★★★★; R19-Strukturkonformität identisch zu daly·dal, chol·chol, or·or-Palindrom', stars: '★★★★★' },
  { id: 'R37', rule: 'R19-Intensivierungsschema gilt ab Quire C auch für <span class="eva">qo-</span>-Präfix-Wortgruppen: <span class="eva">qoky·qoky</span> (und weil · und weil), <span class="eva">qokchy·qokchy</span> (und wie Blässe · und wie Blässe) — Dopplung verstärkt kausale Verbindung oder diagnostischen Befund', evidence: 'f18v P.2: qokchy·qokchy (Corpus-Erstbeleg qo-Dopplung); f18v P.3: qoky·qoky (2. Beleg, verschiedene Lemmata); f26v P.5: qotedy·qotedy (3. Beleg, neues Lemma); R43 erfüllt: f18v + f26v = 2 Folios', stars: '★★★★' },
  { id: 'R38', rule: '<span class="eva">{plant}</span>-Marker am Paragraphenanfang = Pflanzenillustration rahmt den nachfolgenden Kolophon-Text strukturell — neue Strukturvariante in Quire C; in Quires A+B steht {plant} nie am Paragraphenanfang — Kandidat', evidence: 'f18v P.10: {plant}yko.dshy.dair.ykol.dom= — Corpus-Erstbeleg der Anfangspositionierung; 0 Belege in Quires A+B', stars: '★★★' },
  { id: 'R39', rule: '<span class="eva">dom=</span> (<span class="heb-sm">דּוֹם</span> = Stille/Ende) als Schlusskolophon-Finale in Sprache A — positiv-neutrale Prognose-Semantik (Stille/Ruhe, kein shol/sheol); bisher nur in Sprache B (f57r) belegt — Kandidat', evidence: 'f18v P.10: dom= — Erstbeleg Spr. A; Parallelbeleg Spr. B: f57r Kolophon-Kontext; dom = neutral/positiv (Stille) vs. shol = negativ (Tod)', stars: '★★★' },
  // ── v6.2 Härtungsmaßnahmen ───────────────────────────────────────────────
  { id: 'R40', rule: '<strong>Kurzwurzel-Konfidenzdeckel v2 (verschärft, v6.3):</strong><br>Ein EVA-Wort, dessen Basiswurzel nach Abtrennung aller validen Präfixe und Suffixe <strong>≤ 3 Konsonanten</strong> enthält, erhält <strong>maximal ★★</strong> (niemals ★★★ oder höher), es sei denn mindestens <strong>zwei</strong> der folgenden Ausnahmebedingungen sind gleichzeitig erfüllt:<br>(a) Funktionswort ≤ 3 EVA-Zeichen gesamt (Konjunktion, Präposition, Artikel, Partikel — keine Ableitungen),<br>(b) Rückwärtstest-Anker (positiver Rückwärtstest, derzeit 23 Anker),<br>(c) Korpusfrequenz ≥ 15× in ≥ 3 verschiedenen Folios mit semantisch konsistentem Kontext.<br>Ist keine oder nur eine Ausnahme erfüllt: HARD CAP ★★ ohne Ausnahme — Kandidat', evidence: '<span class="eva">or</span> → ★★★★ bleibt (b ✓ + c ✓: 52×, 5 Folios); <span class="eva">chor</span> → ★★★★ bleibt (b ✓ + c ✓: 47×, 5 Folios); <span class="eva">daiin</span> → ★★★★ bleibt (b ✓ + c ✓: 38×, 5 Folios); <span class="eva">shol</span> → ★★★ bleibt (b ✓ + c ✓: 19×, 5 Folios); <span class="eva">ky</span> → ★★★ bleibt (a ✓ + b ✓); <span class="eva">dy</span> → ★★ (a nur 1/2 — zu lang für Grenzfall)', stars: '★★★' },
  { id: 'R41', rule: '<strong>Präfix-Hierarchie-Protokoll (v6.4 erweitert):</strong><br>Valide Reihenfolge: [<span class="eva">d-</span> Relativ (R45)] → [Konj.: <span class="eva">o-/qo-/v-</span>] → [Präp.: <span class="eva">l-/b-/k-/m-</span>] → [Kompositum: <span class="eva">op-/of-</span> = עַ+פֶּ] → [Artikel: <span class="eva">ha-</span>] → [Basis].<br>Folgende Strukturen sind <strong>ungültig</strong> und müssen verworfen werden:<br>(a) Präposition direkt vor Konjunktion ohne Basiswurzel-Trennung,<br>(b) mehr als 2 geschichtete Präfixe aus verschiedenen Klassen an einem Token,<br>(c) <span class="eva">sho-</span>-Präfix kombiniert mit positivem Prognose-Vokabular (<span class="eva">or, chaiin, okal</span>) im gleichen Token — Kandidat', evidence: 'Ausnahme: <span class="eva">qo-k-</span>-Kombination in Quire C (R33) ist validierte Einzelklasse, kein Doppel-Präfix; illegale Beispiele: <span class="eva">l-o-[Wort]</span> (Präp.+Konj.), <span class="eva">o-qo-[Wort]</span> (Doppel-Konj.), <span class="eva">qo-k-ch-[Wort]</span> (> 2 Präfix-Layer); neu: d-Relativpräfix (R45) bildet äußerste Schale; op-/of- (R48, Quire H) als Koordinatenmarker im astronomischen Register f58r P.26', stars: '★★★' },
  { id: 'R42', rule: '<strong>Kongruenzpflicht für ★★★★+:</strong><br>Ein Mapping-Eintrag erhält ★★★★ oder höher nur wenn (a) das zugeordnete Nomen in Genus und Numerus kompatibel ist und (b) die Kongruenz durch ≥ 1 unabhängigen Parallelbeleg im Corpus bestätigt wird. ★★★-Einträge ohne Kongruenztest bleiben vorläufig; bei erster Nachanalyse geprüft — Scheitern → <strong>Herabstufung auf ★★</strong> — Kandidat', evidence: '<span class="eva">ykchaiin</span> Mask.Sg. + <span class="eva">aiin</span> Sg.mask. ✓ f9r; <span class="eva">ykchy</span> Mask.Sg. + <span class="eva">chy</span> Sg. ✓ f11v; <span class="eva">ykchor</span> Mask.Sg. + <span class="eva">chor</span> Sg. ✓ f11r; <span class="eva">ykshol</span> Mask.Sg. + <span class="eva">shol</span> Sg. ✓ f15r — 4/4 Kongruenztests bestanden; ykam/ytor f18v: Parallelbeleg noch ausstehend', stars: '★★★' },
  // ── v6.3 Härtungsmaßnahmen (empirisch ausgelöst durch GibberishTest) ──────
  { id: 'R43', rule: '<strong>Multi-Folio-Validierungspflicht (v6.3):</strong><br>Ein Lexikoneintrag erhält ★★★ oder höher nur dann, wenn er in <strong>mindestens 2 verschiedenen Folios</strong> mit semantisch kompatiblem Kontext belegt ist.<br>Ausnahme: Einzelfolio-Beleg als <strong>★★★ Kandidat</strong> möglich, sofern ≥ 8 unabhängige Belege im Folio und kein semantischer Widerspruch zu anderen Lexikoneinträgen — Bestätigung durch zweiten Folio-Beleg innerhalb der nächsten 5 analysierten Folios erforderlich; andernfalls automatische Rückstufung auf ★★ — Kandidat', evidence: '<span class="eva">ykam</span> f18v (4×, Erstbeleg) → ★★★ Kand. bis Quire-H-Bestätigung; <span class="eva">ytor</span> f18v (3×) + f58r P.30 (R43 erfüllt) → <strong>★★★★</strong>; <span class="eva">ykair</span> f16r (1×) → ★★ provisorisch (unter Minimum 8×); <span class="eva">kchom</span> f001r (2×) → ★★★ Kand. (Flag bleibt)', stars: '★★★' },
  { id: 'R44', rule: '<strong>Konsekutive Kurzwurzel-Sequenzsperre (v6.3):</strong><br>Wenn zwei aufeinanderfolgende EVA-Wörter <strong>beide</strong> eine Basiswurzel mit ≤ 3 Konsonanten haben, kann die Sequenz insgesamt nur dann ★★★ oder höher erreichen, wenn:<br>(a) mindestens <strong>eines</strong> der beiden Wörter durch den Rückwärtstest validiert ist (R40-Ausnahme b), <strong>und</strong><br>(b) die morphologische Kongruenz zwischen beiden Wörtern dem R42-Standard genügt (Genus/Numerus-Kompatibilität mit Parallelbeleg).<br>Ist nur eine oder keine Bedingung erfüllt: Sequenz ★★. Nicht anwendbar auf Funktionswort-Hauptwort-Paare — Kandidat', evidence: '<span class="eva">ykchaiin</span> + <span class="eva">daiin</span>: daiin Rückwärtstest-Anker (b ✓) + R42-Kongruenz ✓ → R44 greift nicht; <span class="eva">ky</span> + <span class="eva">chor</span>: Funktionswort-Ausnahme → R44 greift nicht; Neues Verb + neues Objekt (je ★★★ Kand.): kein Anker, kein Parallelbeleg → Sequenz ★★; <span class="eva">shol</span> + neues Adj. (Einzelbeleg): shol Anker ✓, R42-Kongruenz fehlt → ★★', stars: '★★★' },
  { id: 'D1/D2', rule: '⚠ <strong>Phonotaktische Warnsignale</strong> (Warnsystem, kein Hard Stop):<br><strong>D1 Doppelkonsonanz-Warnung</strong> — zwei identische Mapping-Ausgaben im Basiswort-Kern (z. B. EVA <span class="eva">rr</span> → ר-ר) erhalten ⚠ Doppelkonsonanz-Flag; erfordert explizite Erklärung (Geminierung/Dagesh, Assimilation, Schreibervarianz).<br><strong>D2 Kehlkopf-Cluster-Warnung</strong> — zwei laryngale/pharyngale Konsonanten nebeneinander (EVA-Mappings h/ch/aiin → ה/ח/ע) erhalten ⚠ Kehlkopf-Cluster-Flag; erfordert morphologische Rechtfertigung. Konfidenz wird in beiden Fällen <em>nicht automatisch</em> reduziert.<br><strong>R45-Ausnahme:</strong> <span class="eva">d-</span>-Anlaut vor Konsonant triggert kein D1-Flag (s. R45) — Kandidat', evidence: 'EVA-Phonologie noch nicht gesichert → kein Hard Stop möglich; D1-Erklärungsoptionen: Dagesh-Verdopplung, partielle Assimilation, Schreibervarianz; D2: Doppel-Laryngal im Mischna-Hebräisch selten und markiert; R45-Ausnahme: 6 D1-Fehlklassifikationen auf f58r durch aramäisches d-Relativpräfix aufgelöst', stars: '★★' },
  // ── v6.4 Härtungsmaßnahmen & Formalisierungen (ausgelöst durch f58r) ──────
  { id: 'R45', rule: '<strong>Aramäisches d-Relativpräfix als morphologische Klasse (v6.4):</strong><br>Das EVA-Zeichen <span class="eva">d-</span> am Wortanfang, unmittelbar gefolgt von einem weiteren Konsonanten ohne Vokalträger, gilt als Aramaismus: aramäisches Relativpräfix <span class="heb-sm">דְּ/דִּי</span> (de-/di- = „von/dessen/welches"). Es ist morphologisch von der Basiswurzel zu trennen.<br><strong>(a) Keine D1-Flags:</strong> <span class="eva">d-</span>-Anlaut vor Konsonant triggert nicht das D1-Warnsignal.<br><strong>(b) Präfix-Hierarchie-Erweiterung:</strong> <span class="eva">d-</span> als Relativpräfix bildet die äußerste morphologische Schale (s. R41 v6.4).<br><strong>(c) Abgrenzung:</strong> <span class="eva">d-</span> als Basiskonsonant (z. B. <span class="eva">dal</span> = <span class="heb-sm">דַּל</span>) erkennt man am folgenden Vokalträger; <span class="eva">d-</span> als Relativpräfix erkennt man an direkter Konsonantenfolge ohne Vokalindikator — Kandidat', evidence: 'f58r: <span class="eva">dshodal</span> (P.2), <span class="eva">dshor</span> (P.4), <span class="eva">dchairam</span> (P.5), <span class="eva">dtor</span> (P.34), <span class="eva">dtshol</span> (P.38), <span class="eva">dchol</span> (P.40) — 6 klare Instanzen; alle durch <span class="heb-sm">דְּ</span>-Relativpräfix vollständig aufgelöst; 6 D1-Fehlklassifikationen zurückgezogen', stars: '★★★' },
  { id: 'R46', rule: '<strong>Wurzelketten-Ausnahme für R44 (v6.4):</strong><br>Wenn ≥ 3 aufeinanderfolgende EVA-Tokens morphologisch nachweislich dieselbe validierte Basiswurzel teilen — als Komposita, Ableitungen, Präfixformen oder Intensivierungen eines einzigen Rückwärtstest-Ankers — greift <strong>R44 nicht</strong>. Begründung: R44 soll zufällige Kollisionen verschiedener schwacher Kurzwurzeln blockieren; eine kohärente Wurzelkette ist das morphologische Gegenteil — bewusste stilistische Amplifikation (vgl. R19, R35).<br><strong>Nachweis-Anforderung:</strong> Explizite Dokumentation der Basiswurzel und aller Ableitungsformen; ein nicht-ableitbares Token bricht die Kette.<br><strong>GibberishTest-Neutralität:</strong> Pseudowörter bilden keine systematischen Wurzelketten — R46 erhöht die Testrate nicht — Kandidat', evidence: 'f58r P.5: <span class="eva">char.ar.al.char.arary.ytalar</span> — 6 Tokens, alle Derivate der validierten Basiswurzel <span class="heb-sm">א-ו-ר</span> (Licht); R44 greift nicht, da keine zufällige Diversität sondern kohärente Intensivierung; semantisch: astronomische Licht-Litanei über Sternglanz', stars: '★★★' },
  { id: 'R47', rule: '<strong>qo-Präfix-Vollintegration ab Quire H (Erweiterung von R33, v6.4):</strong><br>Das <span class="eva">qo-</span>-Präfix (<span class="heb-sm">וְ</span>) ist in Quire H (Beinecke VIII) vollständig in Sprache A integriert — Belegdichte ~8 % der Tokens, gleichauf mit Sprache B auf f57r. Quire H ist keine Übergangszone (wie Quire C per R33), sondern ein voll-integrierter <span class="eva">qo-</span>-Bereich.<br><strong>Quire-Progressionsskala:</strong><br>Quires A+B: absent<br>Quire C: emergierend (R33)<br>Quire T: vollständig<br>Quire H: <strong>vollständig</strong>.<br><strong>Konsequenz für R1:</strong> R1 gilt nur für Quires A+B (Beinecke I+II).<br><strong>Offene Frage:</strong> Quires D–G (Beinecke IV–VII) noch nicht analysiert — monotone Zunahme erwartet — Kandidat', evidence: 'f58r (Quire H, Spr. A): 28+ <span class="eva">qo-</span>-Formen in ~350 Token (Stichprobe: <span class="eva">qor, qokaiin, qocphody, qokalam, qotyshey, qokaldy, qotaily</span> u. a.); Vergleich: f17r/v Quire C (R33): 13 Belege/250 Token; f57r Quire T (Spr. B): ~8 %; f001r Quire A: 0/260 Token', stars: '★★★' },
  { id: 'R48', rule: '<strong>Randstern-System Quire H — astronomisches Register (v6.4):</strong><br>Das Randstern-System (bisher formal für f103r/v als medizinisches Register-Trennsystem dokumentiert) ist auch in Quire H aktiv. Auf f58r markieren drei goldene Randsterne drei Textblöcke.<br><strong>Morphologie:</strong> 6-Zacken (kein Kern) · 7-Zacken (kleiner Kern) · 8-Zacken (größerer Kern) — steigende Komplexität korrespondiert mit steigender astronomischer Spezifität.<br><strong>Parallele zu f103r:</strong> Auf f103r markieren Sternmorphologien Schweregrade medizinischer Fälle; auf f58r markieren sie astronomische Registerkategorien. Das zugrunde liegende Prinzip ist register-übergreifend identisch: Randstern = strukturell funktionaler Gliederungsmarker, nicht dekorative Illustration — Kandidat', evidence: 'f58r: Stern 1 (6-Zacken, kein Kern) über P.1 → Block P.1–P.15 (~150 Token, generisches Sternen-Register); Stern 2 (7-Zacken, kleiner Kern) über P.16 → Block P.16–P.25 (~100 Token, Planetenreihe); Stern 3 (8-Zacken, größerer Kern) über P.26 → Block P.26–P.40 (~155 Token, op-Koordinatenformat); Kolophone (=) an P.15 und P.25 als Blockabschluss', stars: '★★★' },
  // ── v6.5 Erweiterungen (ausgelöst durch f19r + f19v — Bifolio bC3) ─────────
  { id: 'R49', rule: '<strong>y+t-Verb-Litanei als Schlusskolophon (v6.5):</strong><br>Eine Sequenz von ≥ 4 aufeinanderfolgenden <span class="eva">y+t</span>-präfigierten Heilungsverben in Finalposition (unmittelbar vor dem =-Schlusskolophon) bildet eine <strong>positive Prognose-Litanei</strong>. Die Verben sind thematisch kohärent (Heilung von Organen oder Zuständen), müssen aber nicht dieselbe Basiswurzel teilen (Unterschied zu R46-Wurzelketten).<br>Dreistufiges Schema: Ursachen-Verb(en) → Illuminations-Verb(en) → Organ-Heilungs-Verb(en). Alle vier Transkriptoren (H, C, F, U) stimmen im einzigen bekannten Beleg vollständig überein — stärkste Transkriptionskonvergenz des Folios — Kandidat', evidence: 'f19v P.12: <span class="eva">yees.ykchol.oty.ytor.ytar.ytchor.ytaiin=</span> (7 y-Verben — Corpus-Rekord): yees (Fieber löschen) → ykchol (alles heilen) → oty (Zeichen) → ytor+ytar (Illumination ×2, R19) → ytchor+ytaiin (Pupille→Auge, Organ-Spezifizierung); semantisch kohärent; alle 4 Transkriptoren (H, C, F, U) identisch — Kandidat, 1 Beleg, erfordert Folgebestätigung', stars: '★★★' },
  // ── v6.6 Erweiterungen (ausgelöst durch f77r — D2-Phonotaktik-Härtetest) ─
  { id: 'R50', rule: '<strong>Galiläische Guttural-Abschwächung — Sprache-B-Vokalklärung (v6.6):</strong><br>Im Sprache-B-Register gilt für EVA-Sequenzen <span class="eva">ee</span> und <span class="eva">oo</span>:<br><strong>(a)</strong> <span class="eva">ee</span> repräsentiert <strong>ausschließlich</strong> den Tsere-Vokal (ֵ) als Vokalmarker — <strong>nicht</strong> als ה+ה (zwei konsonantische Laryngale).<br><strong>(b)</strong> <span class="eva">oo</span> repräsentiert <strong>ausschließlich</strong> Vav-Holam (וֹ) als Vokalmarker — <strong>nicht</strong> als ו+ו oder ע+ע.<br><strong>(c)</strong> D2-Warnungen, die ausschließlich durch Interpretation B (<span class="eva">ee</span>→ה+ה) ausgelöst werden, werden <strong>automatisch suspendiert</strong>, sofern das Token morphologisch einer validierten Sprache-B-Form entspricht.<br><strong>Historische Grundlage:</strong> Doppelschreibung des schwachen Laryngals zur Vokaldehnung ist in galiläischem Westaramäisch, palästinensischen Targum-Handschriften und Geniza-Texten gesichert.<br><strong>Ausnahme:</strong> Tokens der Struktur <span class="eva">ch</span>+[Vokal]+<span class="eva">ol</span> (ח-ע-ל) werden von R50 nicht erfasst — genuine ח-ע-Benachbarung im Konsonantenskelett (s. Residualfälle).<br><strong>v7.2-Beobachtung: ot-Kompositum-Dreikette</strong> — f24v P.2: <span class="eva">otol+otaiir+otchos</span> = drei ot-Komposita in Folge (strukturelle Intensivierung durch Dreifach-ot)', evidence: 'Quire M (f77r): D2-Warnungen 42→3 (93 % Reduktion); häufigste Tokens: <span class="eva">qokeedy</span>, <span class="eva">qoteedy</span>, <span class="eva">cheedy</span>, <span class="eva">sheedy</span>, <span class="eva">qokeey</span>, <span class="eva">cheey</span>, <span class="eva">sheeol</span>; Residualfälle: <span class="eva">cheeol</span> (P.21), <span class="eva">cheol</span> (P.24, P.38). Zodiak-Register (Quire K, 4 Folios, v6.9): 30+ ee-Tokens in f71r/f71v/f72r1/f72r2, kein D2-Gegenbeispiel — <strong>R43 erfüllt: 2. vollständiges Register, ★★★ → ★★★★</strong>. v7.2: ot-Kompositum-Dreikette f24v P.2 (otol+otaiir+otchos) — Beobachtung', stars: '★★★★' },
  // ── v6.8 Erweiterungen (ausgelöst durch f21r + f21v — Bifolio bC4 Abschluss) ─
  { id: 'R51', rule: '<strong>Illustrationszwickel-Einschübe — Platzmangel-Querverweise (v6.8):</strong><br>Wenn ein Voynich-Paragraph durch mehrere aufeinanderfolgende <span class="eva">{plant}</span>-Marker gerahmt ist und nur 1–3 Zeichen zwischen zwei Markern oder am Paragraphenende trägt — insbesondere wenn<br>(a) diese Fragmente keine vollständigen Sätze bilden,<br>(b) die Zeichenqualität sich gegenüber dem Haupttext verschlechtert (!!!-Notation), und<br>(c) mehrere solcher Fragmentparagraphen aufeinanderfolgen —<br>dann handelt es sich möglicherweise um nachträgliche <strong>Kreuzreferenz-Einschübe</strong> des Schreibers in freie Zwickel der Pflanzenillustration. Inhaltlich: kurze Abkürzungspartikel oder Wortfragmente, die auf verwandte Rezepte oder therapeutische Kategorien verweisen. Erste Regel, die <strong>paratextuelle Schreiber-Praktiken</strong> im Voynich-System formalisiert — Kandidat', evidence: 'f20v P.7 (<span class="eva">s</span> vor {plant}), P.8 (<span class="eva">d.s</span> vor {plant}), P.9 (<span class="eva">d.s!!!!!!</span> vor {plant}) — drei Belege auf einem Folio, qualitative Eskalation; f21v P.7 (<span class="eva">s</span> vor sheaiin + {plant}) — zweiter Folio-Beleg → Aufstufung auf ★★★ (2 Folios); f22v P.4 (<span class="eva">saiin</span> als Vollwort zwischen 2×{plant} — strukturell stärkstes Beispiel: שׂ+עַיִן = „gleich dem Auge") + P.10 (<span class="eva">s</span> vor {plant}) — 6 Belege über 3 Folios (R43 erfüllt: ≥3 Folios) → ★★★ gesichert', stars: '★★★' },
  // ── v6.9 Erweiterungen (ausgelöst durch bK1: f71r + f71v + f72r1 + f72r2 — Zodiak-Tetraptychon) ─
  // ── v7.0 Erweiterungen (ausgelöst durch f22r + f22v — Bifolio bC3 Abschluss) ─
  // ── v7.1 Erweiterungen (ausgelöst durch f23r + f23v — Bifolio bC2 Abschluss) ─
  { id: 'R53', rule: '<strong>Pflanzen-Titel-Duplikation (v7.1 → ★★★★ ab v7.3):</strong><br>Wenn ein Voynich-Folio einen T-Klassen-Titel (am Folioende, nicht P-Klasse) aufweist, bildet das Titeltoken den <strong>semantischen Kern der Pflanzenidentifikation</strong>. R53 differenziert drei Subtypen:<br><strong>Subtyp A</strong> (R35-Duplikation = Zustandsbeschreibung des pathologischen Zustands, gegen den die Pflanze eingesetzt wird; Format: <span class="eva">[Duplikation+Direktional=]</span>);<br><strong>Subtyp B</strong> (Emphase-Direktional = therapeutischer Heilungsbefehl; Format: <span class="eva">[ee-Emphase+Direktional=]</span>);<br><strong>Subtyp C</strong> (Deskriptiv/Identifikatorisch = Pflanze wird durch ihre diagnostischen Leitzeichen beschrieben; Format: <span class="eva">[Zeichen-Kompositum+Direktional=]</span>).<br>Unterschied zu R35 (Vollheilungs-Emphase): R53 ist auf T-Klassen-Titelposition am Folioende beschränkt. R43 Mehrfachbestätigung: vier T-Klassen-Folios — ★★★★', evidence: '<strong>Beleg 1</strong> f22v T.16: <span class="eva">daldalol=</span> (dal·dal+ol) — Subtyp A: R35-Duplikation; semantisch: doppelte Schwäche des Joches; <strong>Beleg 2</strong> f23v P.12: <span class="eva">eeeoly=</span> ({plant}-Titel) — Subtyp B: Dreifach-ee-Emphase + Direktional; semantisch: therapeutischer Auftrag zum Licht; <strong>Beleg 3</strong> f24r T.20: <span class="eva">sam.chorly=</span> — T-Klassen-Formel: sham + kor + li; <strong>Beleg 4</strong> f25r T.7: <span class="eva">dair.otaiir.otosy=</span> — Subtyp C (deskriptiv/identifikatorisch): Identifikationsformel Zeichen-Augenlicht; divergente interne Struktur der Subtypen bestätigt Differenzierung; R43 Mehrfachbestätigung (4 Folios, 3 Subtypen) → ★★★★', stars: '★★★★' },
  { id: 'R52a', rule: '<strong>Determinans-y im Zodiak-Sternlabel-Register (v6.9):</strong><br>Sternlabeln in Zodiak-Diagrammen enden in ≈ 47 % der Fälle auf <span class="eva">-y</span>, <span class="eva">-dy</span> oder <span class="eva">-ody</span>. Diese Suffixe fungieren als <strong>aramäischer Status Emphaticus</strong> (bestimmter Artikel in Suffixposition, entsprechend -א/-ā in östlichem Aramäisch). Das Suffix ist optional — der nackte Kernstamm existiert parallel (<span class="eva">okal=</span> neben <span class="eva">okaly=</span>). Nach Suffix-Abzug sind alle resultierenden Kernstämme morphologisch intakt und semantisch kohärent. Streuung: 40–53 % über alle vier Panels konsistent. Zusätzliche Suffix-Varianten im Zodiak-Register: <span class="eva">-ary</span>, <span class="eva">-aly</span>.', evidence: 'f71r (53 %: 8/15), f71v (47 %: 7/15), f72r1 (40 %: 6/15), f72r2 (47 %: 14/30) — 4 Folios · 75 Labels · 35 Belege; Minimalpaar-Kontrolle: <span class="eva">okal=</span> (3×: S1.3, S1.5, S1.12) vs. <span class="eva">okaly=</span> (2×: S1.4, S1.12) in f72r2 — Suffix als optionaler Determinant belegt, nicht als Wortbildungselement; keine R40-Konflikte nach Suffix-Abzug', stars: '★★★★' },
  // ── v7.2 Erweiterungen (ausgelöst durch f24r + f24v — Bifolio bC1 Abschluss) ─
  { id: 'R55', rule: '<strong>or-Reduplikation als Kolophon-Abschluss (v7.2 — Kandidat ★★):</strong><br>Die Verdoppelung <span class="eva">oro=</span> (<span class="heb-sm">אֹ+ר+אֹ</span>, Licht-Licht-Palindrom) in unmittelbarer Kolophon-Finalposition (<span class="eva">=</span>-Marker) markiert den positivsten Heilungsabschluss des zugehörigen Textblocks. Unterschied zu R15 (Paradigma-Wiederholungsreihen): R55 ist auf das or-Lexem beschränkt und palindromisch konstruiert. Latente Unterregel der R15-Familie — Kandidat', evidence: 'f24v P.5: <span class="eva">oro=</span> — Corpus-Erstbeleg (1 Beleg); oro-Frist abgelaufen (f29v). Validierungsbedarf bei erneutem Auftreten. Herabgestuft von ★★★ auf ★★ Kand. (v8.1)', stars: '★★' },
  { id: 'R56', rule: '<strong>sho.sho-Emphase (v7.2 → ★★★ validiert v7.7):</strong><br>Die direkte Wortwiederholung <span class="eva">sho.sho</span> ohne Genitivbrücke bildet eine eigenständige Emphase-Kategorie. Unterschied zu R24 (<span class="eva">shol·dy·…·shol</span> = Emphase-Dopplung mit Genitiv-Brücke): R56 verwendet keine Brückenpartikel. Unterschied zu chotshol (f21v): dort ist sho als Präfix in ein Kompositum eingebettet; R56 beschreibt Wortwiederholung auf Token-Ebene', evidence: 'f24v P.14: <span class="eva">sho.sho</span> — Corpus-Erstbeleg; f27v P.7: <span class="eva">sho·sho</span> — Folgebeleg (R43 erfüllt: 2 Folios) → ★★★ validiert', stars: '★★★' },
  // ── v7.3 Erweiterungen (ausgelöst durch f25r + f25v — Bifolio bD1 Eröffnung) ─
  { id: 'R58', rule: '<strong>3×daiin-Konzentration in einer Zeile (v7.3 → ★★★★ validiert v8.7):</strong><br>Wenn drei <span class="eva">daiin</span>-Tokens in einer einzigen Paragraph-Zeile auftreten, bildet dies eine <strong>maximale Urteils-Konzentration</strong>, die über das bekannte Doppelurteil (R19 daiin·daiin = Emphase-Dopplung) hinausgeht. Semantisch: dreifaches Urteil in einer Zeile = absolutes diagnostisches Vollurteil. Unterschied zu R19 (Intensivierungsrhetorik): R19 beschreibt Wiederholungsreihen allgemein; R58 ist spezifisch auf drei daiin-Vorkommen in einer einzigen Paragraph-Zeile beschränkt. Unterschied zu R9 (Refrain-Wörter 3–5× pro Folio): R9 zählt folio-weite Häufigkeit, R58 beschreibt Zeilendichte', evidence: 'f25v P.2: <span class="eva">dchor.cthor.chor.daiin.s.okeeaiin.daiin.ckhey.daiin</span> — Corpus-Erstbeleg (alle H/C/F einig); f30v — 2. Beleg; f32v P.9: <span class="eva">otchol.daiin.daiin.ctho.daiin.qotaiin</span> — 3. Folio-Beleg (H/C/F/U konsistent); R43-Frist erfüllt: f25v + f30v + f32v = 3 unabhängige Folios → ★★★★ validiert', stars: '★★★★' },
  // ── v7.4 Erweiterungen (Härtetests f1r + f1v — Quire A, bA1) ─────────────
  { id: 'R59', rule: '<strong>qo als isolierter Konnektiv-Token (v7.4 → ★★★ validiert v7.8):</strong><br>Das EVA-Token <span class="eva">qo</span> in <strong>isolierter Einzelwort-Position</strong> am Beginn einer Paragraphenzeile repräsentiert das bare וְ (Vav conjunctivum als Partikel), <strong>nicht</strong> das Verbund-Präfix <span class="eva">qo-</span> im Sinne von R1. Es erscheint als grammatische Brücke zwischen zwei inhaltlich zusammengehörigen Paragraphen eines Folio-Eintrags. In Sprache A (Quire A) maximal 1× pro Folio belegbar.<br><strong>Abgrenzung von R1:</strong> R1 (<span class="eva">qo-</span> Verbundpräfix): qo + Stamm als ein Token → Sprache B exklusiv in Quires A+B; R59 (qo Einzeltoken): qo als alleinstehendes Wort, gefolgt von Punkt-Separator → auch in Sprache A möglich', evidence: 'f1v P.7: <span class="eva">qo.ol.choiees.cheol.dol.cthey-</span> — Erstbeleg (alle 4 Transkriptoren H/C/D/F einig); f28r P.1: Folgebeleg (2. Folio) → R43 erfüllt (f1v + f28r = 2 Folios) → ★★★ validiert', stars: '★★★' },
  // ── v8.7 Erweiterungen (ausgelöst durch f31r–f34v — Quire D Abschluss + Quire E) ─
  { id: 'R61', rule: '<strong>ol+[Ankerwort] — Intensivierungsformel (v8.7 — Kandidat ★★★):</strong><br>Das Präfix <span class="eva">ol</span> (<span class="heb-sm">עַל</span> = über/auf) unmittelbar vor einem validierten Ankerwort bildet eine <strong>Intensivierungsformel</strong> für kritische diagnostische oder therapeutische Zustände. Die ol-Formel markiert semantisch eine „Überwindung" oder direkte „Konfrontation" mit dem genannten Zustand.<br><strong>Abgrenzung von R59</strong> (<span class="eva">qo</span> = Vav conjunctivum): R61 verwendet das spezifische <span class="heb-sm">עַל</span>-Präfix statt qo (Vav). R59 verbindet Paragraphen; R61 intensiviert einen Einzelterm.<br><strong>Positionstendenz</strong> (vorläufig): <span class="eva">ol+Ankerwort</span> erscheint häufig unmittelbar vor {plant}-Marker — möglicher Therapie-Direktional.<br><strong>Register und Quire-Reichweite</strong>: Belege aus Sprache A (f34r) und Sprache B (f31r, f31v, f33v, f34v) — cross-register; aus Quire D (f31r–f32v) und Quire E (f33v–f34v) — cross-quire — Kandidat', evidence: '<span class="eva">olsheol</span> (f31r P.11) = über Scheol; <span class="eva">olteedam</span> (f31v P.7) = über das Blut der Zeit; <span class="eva">olaiin</span> (f33v P.6) = über das Auge; <span class="eva">oldam</span> (f34r P.7 + f34v P.2) = über das Blut; <span class="eva">oldar</span> (f34v P.4) = über den Leuchtenden; <span class="eva">olchdaiin</span> (f34v P.7) = über Blässe-Urteil — 6 Belege in einer Sitzung, alle Ankerwörter ★★★★★-Klasse; Steigerungsform: <span class="eva">qoldar</span> (f34v P.4) = qo + ol + dar = dreistufiges Präfix (maximale Intensivierung)', stars: '★★★' },
  // ── v8.3 Erweiterungen (ausgelöst durch {plant}-Positionskodierung — 11 Folios) ─
  { id: 'R60', rule: '<strong>R60 — Pharmakologische Pflanzenteil-Annotation (★★★★, Corpus-übergreifend; Korollar 3 ★★★★★)</strong><br>Das Voynich-Kräuterkorpus encodiert den Pflanzenteil, aus dem ein Präparat gewonnen wird, durch die <strong>vertikale Position</strong> des Texts relativ zur Pflanzenillustration. Strukturelles Designprinzip des Manuskripts, kein ästhetisches Layout-Element. Das Layout selbst ist ein Informationsträger: es vermittelt ohne explizite Beschriftung, <em>mit welchem</em> Pflanzenteil ein Rezept zubereitet wird.<br><strong>Layout-Typen:</strong><br><strong>Typ A</strong> (Apex-Text: gesamter Text über Pflanze = Blüten/Früchte/Triebspitzen als Einheit, f20r, f21r, f57r, f33r, f005r, f006r, f009r, f010r)<br><strong>Typ B</strong> (Bilateral-Blüte: Indikation links + Therapie rechts auf gleicher Blüten-Höhe, f15r, f28r, f1v)<br><strong>Typ C</strong> (Vertikale Zonentrennung: oberer Block = FLOS/FRUCTUS, unterer Block = FOLIUM/CAULIS, f14r, f16r, f30r, f13v, f002r, f002v, f003v, f004r, f007r)<br><strong>Typ D</strong> (Interweaved: jede Textzeile neben anderem Pflanzenteil, hochdifferenziert, f30r P.3–P.12, f003r, f008r).<br><em>Fehlende <span class="eva">{plant}</span>-Marker (Typ f21r) = Ganzpflanzen-Präparat ohne Teilunterscheidung — medizinhistorisch korrekt für Thymian/Kräuter (TOTUS). A contrario-Beweis für das Kodierungsprinzip.</em><br><strong>Korollar 1 (v8.3): Sprachregister-Unabhängigkeit ★★★</strong> — Das Pflanzenteil-Kodierungsprinzip gilt für <strong>beide Sprachregister</strong> (Sprache A UND Sprache B). Belege: f57r (Typ A, Quire H, Spr. B), f33r (Typ A, Quire E, Spr. B). 2 Belege, 0 Gegenbeispiele.<br><strong>Korollar 2 (v8.3): Ikonographische Toxizitäts-Warnung ★★★</strong> — Das Mandrake-Menschenkopf-Motiv (f33r) bildet eine ikonographische Entsprechung zum textuellen Farbcode-Korollar: Wo der Text schweigt (keine Verschreibung), spricht das Bild (Menschenkopf = Gefahr). Textuelle und bildliche Kodierungsebene kommunizieren dieselbe pharmakologische Information.<br><strong>Korollar 3 (v8.4/v8.7): FOLIUM-Textfreiheit ★★★★★</strong> — Die FOLIUM-Zone (Blätter) hat systematisch keinen Text, <em>unabhängig von der Blattfarbe</em>. Gilt für grüne Blätter (f002v, f005r), dunkel übermale Blätter (f002r), rot-geschattete Blätter (f003r, f004r) und gezähnte Blätter (f010r). Der Stängel (CAULIS) hat Text; die Blätter (FOLIUM) haben keinen Text. Interpretation: Blätter sind im Voynich-System keine primären Heilmittel-Einheiten. v8.7: 25/25 Folios bestätigt (f32r/v + f33v + f34r/v ergänzt), 0 Gegenbeispiele → 25-Folio-Schwelle überschritten → ★★★★★.<br><strong>Korollar 4 (v8.4 NEU): Drei-Kategorien-Farbcode ★★★★★</strong> — Rot im Kräuterkorpus ist nicht uniform. Drei distinkte Kategorien: (1) Pharmakologisches Dunkelrot = homogene Terracotta-Füllfläche → kein Text (12 Wurzel-Belege + 3 Nicht-Wurzel-Belege, 0 Gegenbeispiele); (2) Illustrationslinien-Rot = Linienzüge/Strichel → kein pharmakologisches Signal; (3) FLOS-therapeutisches Rot = Punkte/Textur für Früchte/Beeren → Text vorhanden (f009r, f006r). Die Maltechnik ist entscheidend: Fläche ≠ Linie ≠ Textur.', evidence: '21/21 analysierten Folios (Quire A f1v–f10r + f13r/v + f14r + f15r + f16r + f22r + f28r + f30r/v + f33r + f57r): Muster I — selektive Annotation (kein Text neben nicht-verschriebenen Teilen) — 0 Gegenbeispiele ★★★★; Stolfi f16r: „interrupted by the plant\'s flower" ★★★★★; <span class="eva">pol</span> (Frucht-Term) an Frucht-Position f22r P.1 — stärkster semantischer Einzelbeweis ★★★★★; f19r: Blüten-Semantik (<span class="eva">saiin+chor</span>) stimmt mit Kornblumen-Pharmakologie (Augenwasser, Konjunktivitis) überein ★★★★★; f21r: keine {plant}-Marker → Thymian-Ganzpflanzen-Präparat ★★★; f14r/f22r/f28r/f30v: rote Wurzeln ohne Text — 4 Belege ★★★★; f25r: Reeds <code>Colors: green,dark-red</code> bestätigt Farbcode unabhängig; f57r + f33r: beide Sprachregister bestätigt ★★★; FOLIUM-Textfreiheit: 25/25 Folios (100 %), 0 Gegenbeispiele — grüne, dunkle, rot-geschattete Blätter alle textfrei; v8.7: f32r/v + f33v + f34r/v ergänzt → 25-Folio-Schwelle → ★★★★★; f009r rote Punkt-Ähre MIT Text = FLOS-therapeutisch (Drei-Kategorien-Bestätigung); f010r rote Ovale OHNE Text = Ebene-2-Nicht-Wurzel-Beleg ★★★★★', stars: '★★★★' },
];
